    &lt;&lt;interface&gt;&gt;
    +SetPartA()
    +SetPartB()
    +SetPartC() 
    +GetProduct() *product
}
class concreteBuilderA {
    +SetPartA()
    +SetPartB()
    +SetPartC() 
    +GetProduct() *productA
}
class concreteBuilderB {
    +SetPartA()
    +SetPartB()
    +SetPartC() 
    +GetProduct() *productB
}
class director {
    &lt;&lt;interface&gt;&gt;       
    +SetBuilder(b builder)
    +Construct() *product
}

class product {
    &lt;&lt;interface&gt;&gt; 
    &#x2F;&#x2F;...
}

class productA {
    &#x2F;&#x2F;...
}
class productB {
    &#x2F;&#x2F;...
}
builder &lt;|.. concreteBuilderA
builder &lt;|.. concreteBuilderB
product &lt;|.. productA
product &lt;|.. productB
director ..&gt; builder : SetBuilder()
director ..&gt; product : Construct()
director ..&gt; product : Construct()


比起不停地修改、维护构造函数以及调用，使用生成器模式只需定义好对应的Builder接口，统一调用Director接口的Construct方法即可。

1. 什么是适配器模式？适配器模式（Adapter Pattern）是一种结构型设计模式，它允许将一个类的接口转换为客户端期望的另一个接口。适配器模式使得原本由于接口不兼容而不能一起工作的类可以协同工作。
就像 “USB-C 转 3.5mm 音频” 转换器。很多新款手机（被适配者 Adaptee）取消了传统的 3.5mm 耳机孔，只提供 USB-C 接口。如果你想使用旧的 3.5mm 插头耳机（客户端 Client），就会遇到接口不兼容的问题。
此时，这个转换器就充当了适配器（Adapter）的角色。它将手机的 USB-C 接口转换为耳机（客户端）所期望的 3.5mm 音频插孔。通过这个小小的转换器，耳机无需任何改动，就能在新手机上继续使用，适配器完美地弥合了两者之间的接口差异。
2. 为什么需要适配器模式？在软件开发中，我们经常会遇到以下几种情况，这时适配器模式就显得尤为重要：

复用现有代码：当一个已存在的类功能很强大，能满足你的大部分需求，但它的接口与你当前系统要求的接口不一致时。重写这个类会耗费大量时间且容易引入错误，而使用适配器则可以在不改变原有代码的基础上，将其“包装”成你需要的样子。

集成第三方库或遗留系统：第三方库或老旧系统的接口通常无法修改。如果它们的接口与你的系统不兼容，适配器可以作为中间层，将这些外部接口转换为系统内部统一的、标准的接口，从而实现无缝集成。

解耦客户端与具体实现：客户端代码只依赖于一个标准的目标接口（Target），而不需要关心背后真正干活的类（Adaptee）是谁，它的接口长什么样。这样一来，当底层的具体实现需要更换时，只需要更换或修改对应的适配器，而客户端代码完全不受影响，增强了系统的灵活性和可维护性。


总而言之，适配器模式遵循了“开闭原则”（对扩展开放，对修改关闭），它允许我们在不修改现有代码的情况下，通过增加新的适配器类来扩展系统的功能。
3. 适配器模式的实现（go）假设我们有一个音乐播放器 MusicPlayer，它依赖一个 Player 接口来播放音乐。
// Player是我们期望的目标接口 (Target)type Player interface &#123;    PlayMusic()&#125;

现在，我们有一个现成的、无法修改的第三方音频库 AwesomePlayer，但它的播放方法是 PlaySound，与我们的 Player 接口不兼容。
// AwesomePlayer 是一个已存在的、接口不兼容的类 (Adaptee)type AwesomePlayer struct&#123;&#125;func (p *AwesomePlayer) PlaySound() &#123;    fmt.Println(&quot;Playing sound with AwesomePlayer&quot;)&#125;

为了让 MusicPlayer 能使用 AwesomePlayer，我们创建一个适配器 AwesomePlayerAdapter。
// AwesomePlayerAdapter 是适配器 (Adapter)type AwesomePlayerAdapter struct &#123;    adaptee *AwesomePlayer // 持有被适配的对象&#125;// NewAwesomePlayerAdapter 创建一个新的适配器实例func NewAwesomePlayerAdapter(adaptee *AwesomePlayer) *AwesomePlayerAdapter &#123;    return &amp;AwesomePlayerAdapter&#123;adaptee: adaptee&#125;&#125;// PlayMusic 实现了 Player 接口，内部调用被适配者的 PlaySound 方法func (a *AwesomePlayerAdapter) PlayMusic() &#123;    a.adaptee.PlaySound()&#125;

现在，客户端代码可以像这样使用：
func main() &#123;    // 创建被适配的对象    awesomePlayer := &amp;AwesomePlayer&#123;&#125;        // 创建适配器，并将其传入    var player Player = NewAwesomePlayerAdapter(awesomePlayer)        // 客户端通过统一的 PlayMusic 接口进行播放，无需关心底层实现    player.PlayMusic() // 输出: Playing sound with AwesomePlayer&#125;

在这个例子中，AwesomePlayerAdapter 成功地将 AwesomePlayer 的 PlaySound 接口转换为了 Player 接口所期望的 PlayMusic 接口，使得客户端可以无缝地使用这个第三方库。
类图：

    classDiagram
    class Player {
        &lt;&lt;interface&gt;&gt;
        +PlayMusic()
    }
    class AwesomePlayer {
        +PlaySound()
    }
    class AwesomePlayerAdapter {
        -adaptee: AwesomePlayer
        +PlayMusic()
    }
    Player &lt;|.. AwesomePlayerAdapter
    AwesomePlayerAdapter &quot;1&quot; *-- &quot;1&quot; AwesomePlayer
    AwesomePlayerAdapter ..&gt; AwesomePlayer : PlayMusic() call PlaySound()

1. 什么是原型模式？一言以蔽之，原型模式（Prototype Pattern）是一种创建型设计模式，它允许客户端直接调用Clone方法来创建一个与已有实例完全一致的新的实例，而不需要知道已有实例的构造函数以及构造参数。
2. 为什么需要原型模式？正如上述，原型模式的主要优势在于它允许客户端直接调用Clone方法来创建一个与已有实例完全一致的新的实例，而不需要知道已有实例的构造函数以及构造参数。这使得原型模式在需要快速创建多个相同对象的场景下非常有用，例如在游戏开发中创建多个相同类型的敌人实例。
3. 原型模式的实现（go）原型模式提供prototype接口，主要需要实现Clone方法，该方法返回一个与已有实例完全一致的新的实例。
中间件代码示例：
type prototype interface &#123;    Clone() prototype&#125;type concreteType struct &#123;    // ...构造参数&#125;func (c *concreteType) Clone() prototype &#123;    return &amp;concreteType&#123;        // ...构造参数    &#125;   &#125;

客户端使用：
func main() &#123;    // 创建一个原型实例    instance := &amp;concreteType&#123;        // ...构造参数    &#125;    // 使用Clone方法创建一个新的实例    newInstance := &amp;instance.Clone().(concreteType)&#125;

类图：

    classDiagram
class prototype {
    &lt;&lt;interface&gt;&gt;
    +Clone() prototype
}
class concreteType {
    &#x2F;&#x2F; ...构造参数
}
prototype &lt;|.. concreteType

1. 什么是桥接模式？桥接模式（Bridge Pattern）是一种结构型设计模式，它的核心思想是将抽象部分与它的实现部分分离，使它们都可以独立地变化。
想象一下电视机和遥控器的关系：

抽象层：遥控器。它定义了高层操作，如 开机()、关机()、换台()。不同的遥控器（如 普通遥控器、智能遥控器）可以有不同的交互方式，但它们都服务于控制电视这个目的。
实现层：电视机。它负责执行具体的操作，如 物理开机()、切换视频源()。不同的电视品牌（如 索尼电视、三星电视）有各自的实现细节。

桥接模式就像是在遥控器中内置一个对电视机实例的引用。遥控器的按钮按下后，会调用它所引用的那台电视机的具体方法。通过这种方式，你可以独立地更换遥控器（从普通遥控器升级到智能遥控器），而无需关心电视机的品牌；同样，你也可以独立地更换电视机（从索尼换成三星），而遥控器无需任何改变。它们通过一个“桥梁”连接，各自演化。
2. 为什么需要桥接模式？当一个类或系统存在多个独立变化的维度时，桥接模式就显得尤为重要。如果不使用桥接模式，我们可能会倾向于使用继承来解决问题，但这会导致类的数量爆炸式增长。
设想一个场景：我们要绘制不同颜色（如红色、蓝色）的形状（如圆形、方形）。

维度一：形状（Circle, Square）
维度二：颜色（Red, Blue）

如果使用继承，我们可能需要创建 RedCircle, BlueCircle, RedSquare, BlueSquare 这样 2 * 2 = 4 个类。如果再增加一种形状（三角形）和一种颜色（绿色），类的数量就会变成 3 * 3 = 9 个。这种“笛卡尔积”式的类爆炸是难以维护的。
桥接模式通过将“形状”和“颜色”两个维度分离来解决这个问题：

抽象部分：Shape (形状)，它包含一个对 Color (颜色) 的引用。
实现部分：Color (颜色)，它是一个接口，有 Red、Blue 等具体实现。

这样，类的数量就从 M * N 变成了 M + N。当需要增加一种新形状或新颜色时，只需增加一个新类，而不会影响到其他部分，完美遵循了开闭原则。
3. 桥接模式的实现（Go）下面我们用 Go 来实现上述的“形状与颜色”的例子。
中间件：
// 1. 实现部分 (Implementor)// Color 是实现部分的接口type Color interface &#123;	ApplyColor() string&#125;// 2. 具体实现 (Concrete Implementors)// RedColor 是一个具体的颜色实现type RedColor struct&#123;&#125;func (r *RedColor) ApplyColor() string &#123;	return &quot;Red&quot;&#125;// BlueColor 是另一个具体的颜色实现type BlueColor struct&#123;&#125;func (b *BlueColor) ApplyColor() string &#123;	return &quot;Blue&quot;&#125;// 3. 抽象部分 (Abstraction)// Shape 是抽象部分的接口，它包含一个对实现部分(Color)的引用type Shape interface &#123;	Draw()&#125;// 4. 扩展抽象 (Refined Abstraction)// Circle 是一个具体的形状，它持有一个 Color 对象type Circle struct &#123;	color *Color&#125;func (c *Circle) Draw() &#123;	fmt.Printf(&quot;Drawing a Circle in %s color.\n&quot;, c.color.ApplyColor())&#125;// Square 是另一个具体的形状type Square struct &#123;	color *Color&#125;func (s *Square) Draw() &#123;	fmt.Printf(&quot;Drawing a Square in %s color.\n&quot;, s.color.ApplyColor())&#125;

客户端代码:
func main() &#123;	// 创建具体的实现对象	red := &amp;RedColor&#123;&#125;	blue := &amp;BlueColor&#123;&#125;	// 创建具体的抽象对象，并将实现对象“桥接”进去	redCircle := &amp;Circle&#123;color: red&#125;	blueSquare := &amp;Square&#123;color: blue&#125;	// 调用方法	redCircle.Draw()   // 输出: Drawing a Circle in Red color.	blueSquare.Draw()  // 输出: Drawing a Square in Blue color.&#125;

类图：

    classDiagram
    class Shape {
        &lt;&lt;interface&gt;&gt;
        +Draw()
    }
    class Circle {
        -color: Color
        +Draw()
    }
    class Square {
        -color: Color
        +Draw() 
    }
    class Color {
        &lt;&lt;interface&gt;&gt;
        +ApplyColor() string
    }
    class RedColor {
        +ApplyColor() string
    }
    class BlueColor {
        +ApplyColor() string        
    }
    Circle --|&gt; Shape
    Square --|&gt; Shape
    Circle --&gt; Color
    Square --&gt; Color
    Circle &quot;1&quot; *-- &quot;1&quot; Color
    Square &quot;1&quot; *-- &quot;1&quot; Color
    RedColor ..|&gt; Color
    BlueColor ..|&gt; Color


在这个例子中，Shape 和 Color 可以独立地进行扩展。如果想增加一个 Green 颜色，只需实现 Color 接口即可；如果想增加一个 Triangle 形状，只需创建一个新的 Triangle 结构体并实现 Draw 方法，而无需改动任何现有代码。

1. 什么是组合模式组合模式（Composite Pattern）是一种结构型设计模式，它允许你将对象组合成树形结构以表示“部分-整体”的层次关系。组合模式使得客户端可以统一地处理个别对象和对象组合。
2. 为什么需要组合模式组合最主要的功能是在整个树状结构上递归调用方法并对结果进行汇总。
3. 组合模式的实现（go）假定一个文件系统，其中包含文件和目录。目录可以包含其他文件和目录。
现在我们需要搜索文件系统中是否包含某个文件。
type Component interface &#123;	Search(keyword string)&#125;type Directory struct &#123;	Name     string	children []Component&#125;func (d *Directory) Search(keyword string) &#123;	if d.Name == keyword &#123;		fmt.Println(&quot;find directory:&quot;, d.Name)		return	&#125;	for _, child := range d.children &#123;		child.Search(keyword)	&#125;&#125;// add 方法用于添加子组件func (d *Directory) Add(child Component) &#123;	d.children = append(d.children, child)&#125;type File struct &#123;	Name string&#125;func (f *File) Search(keyword string) &#123;	if f.Name == keyword &#123;		fmt.Println(&quot;find file:&quot;, f.Name)		return	&#125;&#125;

客户端代码
func main() &#123;    root := &amp;Directory&#123;Name: &quot;root&quot;&#125;    dir1 := &amp;Directory&#123;Name: &quot;dir1&quot;&#125;    dir2 := &amp;Directory&#123;Name: &quot;dir2&quot;&#125;    file1 := &amp;File&#123;Name: &quot;file1&quot;&#125;    file2 := &amp;File&#123;Name: &quot;file2&quot;&#125;    root.Add(dir1)    root.Add(dir2)    dir1.Add(file1)    dir2.Add(file2)    root.Search(&quot;file1&quot;)    root.Search(&quot;file2&quot;)    root.Search(&quot;dir1&quot;)    root.Search(&quot;dir2&quot;)&#125;   

类图

    classDiagram
    class Component {
        &lt;&lt;interface&gt;&gt;
        +Search(keyword string)
    }
    class Directory {
        +Name string
        -children []Component
        +Add(child Component)
        +Search(keyword string)
    }
    class File {
        +Name string
        +Search(keyword string)
    }
    Component &lt;|.. Directory
    Component &lt;|.. File
    Directory &quot;1&quot; o-- &quot;n&quot; Component

1. 什么是外观模式外观模式是一种结构型设计模式， 能为程序库、 框架或其他复杂类提供一个简单的接口。
2. 为什么需要外观模式外观模式的主要目的是简化复杂系统的使用。它通过提供一个简单的接口，隐藏系统的复杂性，使客户端代码更易于理解和使用。
3. 外观模式的实现（go）以计算机开机为例，展示外观模式的实现。
// 子系统：CPUtype CPU struct&#123;&#125;func (c *CPU) Start()    &#123; fmt.Println(&quot;CPU: start&quot;) &#125;func (c *CPU) Shutdown() &#123; fmt.Println(&quot;CPU: shutdown&quot;) &#125;// 子系统：内存type Memory struct&#123;&#125;func (m *Memory) LoadOS() &#123; fmt.Println(&quot;Memory: load OS into memory&quot;) &#125;func (m *Memory) Clear()  &#123; fmt.Println(&quot;Memory: clear&quot;) &#125;// 子系统：磁盘type Disk struct&#123;&#125;func (d *Disk) ReadBootSector() &#123; fmt.Println(&quot;Disk: read boot sector&quot;) &#125;// 外观：计算机type ComputerFacade struct &#123;	cpu  *CPU	mem  *Memory	disk *Disk&#125;func NewComputerFacade() *ComputerFacade &#123;	return &amp;ComputerFacade&#123;		cpu:  &amp;CPU&#123;&#125;,		mem:  &amp;Memory&#123;&#125;,		disk: &amp;Disk&#123;&#125;,	&#125;&#125;// 对外暴露的简化接口：开机流程func (c *ComputerFacade) PowerOn() &#123;	fmt.Println(&quot;== PowerOn ==&quot;)	c.disk.ReadBootSector()	c.cpu.Start()	c.mem.LoadOS()	fmt.Println(&quot;System is up.&quot;)&#125;// 对外暴露的简化接口：关机流程func (c *ComputerFacade) PowerOff() &#123;	fmt.Println(&quot;== PowerOff ==&quot;)	c.cpu.Shutdown()	c.mem.Clear()	fmt.Println(&quot;System is down.&quot;)&#125;

客户端
func main() &#123;	pc := NewComputerFacade()	pc.PowerOn()	pc.PowerOff()&#125;

类图

    classDiagram
    class CPU {
        +Start()
        +Shutdown()
    }
    class Memory {
        +LoadOS()
        +Clear()
    }
    class Disk {
        +ReadBootSector()
    }
    class ComputerFacade {
        -cpu: CPU
        -mem: Memory
        -disk: Disk
        +NewComputerFacade()
        +PowerOn()
        +PowerOff()
    }
    ComputerFacade *-- CPU : uses
    ComputerFacade *-- Memory : uses
    ComputerFacade *-- Disk : uses
    ComputerFacade ..&gt; CPU : Start()
    ComputerFacade ..&gt; Memory : LoadOS()
    ComputerFacade ..&gt; Disk : ReadBootSector()
    ComputerFacade ..&gt; CPU : Shutdown()
    ComputerFacade ..&gt; Memory : Clear()

1. 什么是责任链模式？责任链模式（Chain of Responsibility Pattern）是一种行为型设计模式，它将请求的发送者和接收者解耦，将这些处理者连成一条链。链上的每个处理者都有一个成员变量来保存对于下一处理者的引用。除了处理请求外，处理者还负责沿着链传递请求。请求会在链上移动，直至所有处理者都有机会对其进行处理，或是中途退出。 2. 为什么需要责任链模式？当处理一个请求、但处理步骤有多种、且依赖于不同的条件时，一种最直观的写法可能是一个巨大的 if-else 结构： func handle(request *Request) &#123; if conditionA(request) &#123; // 处理 A &#125; else if conditionB(request) &#123; // 处理 B &#125; else if conditionC(request) &#123; // 处理 C &#125; else &#123; // 默认处理 &#125;&#125;
这种代码的问题显而易见，每当需要增加一种新的处理方式，都必须修改 handle 函数，风险很高。 责任链模式就是为了解决这些问题而生的。它将这些处理逻辑拆分成独立的处理者对象，并将它们链接成一条链。当请求到来时，它会沿着链传递，直到处理流程结束为止。 核心收益：
发送者与接收者解耦：发送者只需要知道链的第一个处理者，而不需要关心请求最终由谁处理，也不需要知道链的结构。 灵活性高：你可以在客户端中随时增加、删除或重新排列链中的处理者，而无需改动现有处理者的代码。 符合单一职责原则：每个处理者都只关心自己的处理逻辑，代码更清晰、更易于维护。
每个Handler之间的调用关系有点类似于组合模式，但是责任链模式是链式调用，而组合模式是树形结构。 3. 责任链模式的实现 (Go)首先需要定义handler接口，它包含一个方法Execute，用于处理请求，以及一个方法SetNext，用于设置下一个处理者。 以及具体的处理者实现： // 处理者接口type Handler interface &#123; Execute(p *client) SetNext(next *Handler)&#125;// 具体的处理者实现type Handler1 struct &#123; next *Handler&#125;// 具体的处理者实现type Handler2 struct &#123; next *Handler&#125;func (h *Handler1) Execute(p *client) &#123; //...Handle 1处理逻辑，然后调用下一个处理者 if h.next != nil &#123; h.next.Execute(p) &#125;&#125;func (h *Handler1) SetNext(next *Handler) &#123; h.next = next&#125;func (h *Handler2) Execute(p *client) &#123; //...Handle 2处理逻辑，然后调用下一个处理者 if h.next != nil &#123; h.next.Execute(p) &#125;&#125;func (h *Handler2) SetNext(next *Handler) &#123; h.next = next&#125;
若客户端处理流程为： client -&gt; Handler1 -&gt; Handler2-&gt;over
则 h1 := &amp;Handler1&#123;&#125;h2 := &amp;Handler2&#123;&#125;h1.SetNext(h2)c := &amp;client&#123;&#125;h1.Execute(c)
类图:
classDiagram class Handler { &lt;&lt;interface&gt;&gt; +Execute(p *client) +SetNext(next *Handler) }
class Handler1 { -next: *Handler +Execute(p *client) +SetNext(next *Handler) }
class Handler2 { -next: *Handler +Execute(p *client) +SetNext(next *Handler) }
class client { &#x2F;&#x2F;... }
Handler &lt;|.. Handler1 Handler &lt;|.. Handler2
Handler1 &quot;1&quot; o--&gt; &quot;1&quot; Handler2 : next client &quot;1&quot; &lt;.. &quot;1&quot; Handler1 : Execute

1. 什么是代理模式代理模式是一种结构型设计模式，它通过引入一个代理对象来控制对另一个对象的访问。代理对象可以在客户端和目标对象之间添加额外的功能，如延迟加载、访问控制、日志记录等。
2. 为什么需要代理模式代理模式的核心价值在于在不改变原始对象（目标对象）代码的前提下，增加额外的控制和功能。它像一个中介，隔离了客户端和真实对象，并在中间“做手脚”。
3. 代理模式的实现 (Go)我们用 Go 实现一个保护代理的例子。假设我们有一个 Web 服务器，希望通过一个 Nginx 代理来限制用户的访问速率。

客户端、代理和真实服务都应遵循同一个接口，这样代理才能“伪装”成真实服务。

// Server 是代理和真实服务器的通用接口type Server interface &#123;	HandleRequest(url, method string) (int, string)&#125;


创建真实服务 (RealSubject)

这是我们真正要保护的后端应用。
// Application 是我们的后端真实服务type Application struct&#123;&#125;func (a *Application) HandleRequest(url, method string) (int, string) &#123;	if url == &quot;/app/status&quot; &amp;&amp; method == &quot;GET&quot; &#123;		return 200, &quot;Ok&quot;	&#125;	if url == &quot;/create/user&quot; &amp;&amp; method == &quot;POST&quot; &#123;		return 201, &quot;User Created&quot;	&#125;	return 404, &quot;Not Found&quot;&#125;


创建代理 (Proxy)

Nginx 代理持有对真实服务的引用，并在处理请求前增加了速率限制的逻辑。
import &quot;fmt&quot;// Nginx 是一个代理，它控制对 Application 的访问type Nginx struct &#123;	application      *Application	maxAllowedReq    int	rateLimiter      map[string]int&#125;func NewNginxServer() *Nginx &#123;	return &amp;Nginx&#123;		application:      &amp;Application&#123;&#125;,		maxAllowedReq:    2,		rateLimiter:      make(map[string]int),	&#125;&#125;// checkRateLimit 检查并更新请求速率func (n *Nginx) checkRateLimit(url string) bool &#123;	n.rateLimiter[url]++	if n.rateLimiter[url] &gt; n.maxAllowedReq &#123;		return false // 超出速率限制	&#125;	return true&#125;// HandleRequest 代理的核心方法func (n *Nginx) HandleRequest(url, method string) (int, string) &#123;	// 在转发请求前，执行额外的逻辑（访问控制）	if !n.checkRateLimit(url) &#123;		return 429, &quot;Too Many Requests&quot;	&#125;	// 将请求转发给真实服务	return n.application.HandleRequest(url, method)&#125;


客户端调用

客户端只与代理（Nginx）交互，并不知道真实服务（Application）的存在。
func main() &#123;	nginx := NewNginxServer()	// 第一次请求 /app/status	code, body := nginx.HandleRequest(&quot;/app/status&quot;, &quot;GET&quot;)	fmt.Printf(&quot;Url: /app/status, Code: %d, Body: %s\n&quot;, code, body)	// 第二次请求 /app/status	code, body = nginx.HandleRequest(&quot;/app/status&quot;, &quot;GET&quot;)	fmt.Printf(&quot;Url: /app/status, Code: %d, Body: %s\n&quot;, code, body)	// 第三次请求 /app/status，将被限流	code, body = nginx.HandleRequest(&quot;/app/status&quot;, &quot;GET&quot;)	fmt.Printf(&quot;Url: /app/status, Code: %d, Body: %s\n&quot;, code, body)&#125;

类图

