    class Client
    class Server {
        &lt;&lt;interface&gt;&gt;
        +HandleRequest(url, method)
    }
    class Application {
        +HandleRequest(url, method)
    }
    class Nginx {
        -application: *Application
        -maxAllowedReq: int
        -rateLimiter: map
        +HandleRequest(url, method)
        -checkRateLimit(url): bool
    }

    Client --&gt; Server : uses
    Server &lt;|.. Application : implements
    Server &lt;|.. Nginx : implements
    Nginx o-- Application : aggregates

1. 什么是命令模式命令模式是一种行为设计模式，它将一个请求封装为一个对象，从而使你可用不同的请求对客户进行参数化。简单来说，就是将请求的发送者和请求的具体操作完全解耦。
2. 为什么需要命令模式？命令模式的核心价值在于解耦。如果没有命令模式，调用者（比如一个按钮 Button）需要直接引用并调用一个具体的操作（比如一个文档 Document 的 save() 方法）。这会导致 Button 和 Document 紧密耦合，Button 无法被复用到其他操作上。
通过引入命令对象，调用者不再关心命令的接收者是谁，也不关心操作如何执行。它只知道“我需要执行这个命令”。
这样的话，调用者和接收者之间没有任何直接引用，各自可以独立变化。而且添加新的命令非常容易，只需创建新的具体命令类，而无需修改现有代码，符合开放&#x2F;封闭原则。
3. 命令模式的实现 (Go)中间件：
// Command 接口定义了一个执行操作的方法type Command interface &#123;    Execute(receiver *Receiver)&#125;// Receiver 是请求的接收者，它知道如何执行与请求相关的操作type Receiver struct &#123;    //...&#125;func (r *Receiver) Action() &#123;    // 执行具体的操作&#125;// Command1 是一个具体的命令类，它实现了 Command 接口type Command1 struct &#123;    //...&#125;func (c *Command1) Execute(r *Receiver) &#123;    r.Action()&#125;// Invoker 是请求的发送者，它持有一个 Command 对象  type Invoker struct &#123;    command *Command&#125;func (i *Invoker) SetCommand(command *Command) &#123;    i.command = command&#125;// ExecuteCommand 是 Invoker 用来间接执行命令的方法func (i *Invoker) ExecuteCommand(r *Receiver) &#123;    i.command.Execute(r)&#125;

客户端
receiver := &amp;Receiver&#123;&#125;command := &amp;Command1&#123;&#125;invoker := &amp;Invoker&#123;&#125;invoker.SetCommand(command)invoker.ExecuteCommand(receiver)

类图：

    classDiagram
    class Invoker {
        -command: *Command
        +SetCommand(command: *Command)
        +ExecuteCommand(receiver: *Receiver)
    }
    class Command {
        &lt;&lt;interface&gt;&gt;
        +Execute(receiver: *Receiver)
    }
    class Command1 {
        +Execute(receiver: *Receiver)
    }
    class Receiver {
        &#x2F;&#x2F;...
        +Action()
    }
    Invoker &quot;*&quot; o--&gt; &quot;*&quot; Command: holds
    Command1  ..&gt;  Receiver: executes
    Command1 ..|&gt; Command : implements

1. 什么是迭代器模式迭代器模式（Iterator Pattern）是一种行为设计模式，它提供一种方法来顺序访问一个聚合对象（Aggregate Object）中的各个元素，而又无需暴露该对象的内部表示。
无论操作的是一个数组、一个链表、一棵树还是一个哈希表，都可以用同样的客户端方式去遍历它（比如一个 for-each 循环），而不关心底层的具体的遍历方式是dfs还是bf或者其他。
它将遍历的逻辑从聚合对象中分离出来，放入一个单独的迭代器对象中。这样，容器只负责存储数据，而迭代器负责遍历数据。
2. 为什么需要迭代器模式？如果没有迭代器模式，客户端代码需要知道聚合对象的内部结构才能进行遍历。例如，遍历数组需要用索引，遍历链表需要用 next 指针。这会导致客户端与数据结构紧密耦合。

客户端无需关心容器的内部实现（是 slice、map 还是 linked list），使得更换或修改容器实现变得容易，不影响客户端代码。
为不同的数据结构提供了统一的遍历方式，简化了客户端代码。
可以为同一个聚合对象提供多种不同的迭代器（如正向遍历、反向遍历）。
符合单一职责原则：聚合对象专注于数据存储，而迭代器专注于遍历，职责清晰。

Go 语言的 for...range 循环就是迭代器模式的一个典型应用，它为数组、切片、字符串、map 和 channel 提供了统一的遍历语法。
3. 迭代器模式的实现 (Go)
对一个二叉树实现迭代器模式，要求迭代器能够按中序遍历二叉树。

// Iterator 是泛型迭代器接口type Iterator[E any] interface &#123;	IsEnd() bool	GetCur() E&#125;// Collection 是泛型聚合接口type Collection[E any] interface &#123;	CreateIterator() Iterator[E]&#125;// TreeNodetype TreeNode[T any] struct &#123;	Val   T	Left  *TreeNode[T]	Right *TreeNode[T]&#125;// BinaryTree 是我们的具体聚合类type BinaryTree[T any] struct &#123;	Root *TreeNode[T]&#125;

InOrder
// InOrderIterator 是具体迭代器类type InOrderIterator[T any] struct &#123;	stack []*TreeNode[T]&#125;// CreateIterator 是 BinaryTree 实现 Collection 接口的方法func (bt *BinaryTree[T]) CreateIterator() Iterator[*TreeNode[T]] &#123;	it := &amp;InOrderIterator[T]&#123;stack: make([]*TreeNode[T], 0)&#125;	// 初始化时，将根节点及其所有左子节点压入栈	it.pushLeft(bt.Root)	return it&#125;// pushLeft 辅助函数，将一个节点及其所有左子节点压入栈func (it *InOrderIterator[T]) pushLeft(node *TreeNode[T]) &#123;	for node != nil &#123;		it.stack = append(it.stack, node)		node = node.Left	&#125;&#125;func (it *InOrderIterator[T]) IsEnd() bool &#123;	return len(it.stack) &lt;= 0&#125;// GetCur 返回当前迭代器指向的节点，且将迭代器指向下一个节点func (it *InOrderIterator[T]) GetCur() *TreeNode[T] &#123;    if(it.IsEnd())&#123;        return nil    &#125;	// 从栈顶弹出一个节点	n := len(it.stack) - 1	node := it.stack[n]	it.stack = it.stack[:n]	// 如果该节点有右子树，则将右子节点及其所有左子节点压栈	if node.Right != nil &#123;		it.pushLeft(node.Right)	&#125;	return node&#125;

func main() &#123;	// 构造一棵二叉树	//      4	//     / \	//    2   5	//   / \	//  1   3	root := &amp;TreeNode[int]&#123;		Val: 4,		Left: &amp;TreeNode[int]&#123;			Val: 2,			Left:  &amp;TreeNode[int]&#123;Val: 1&#125;,			Right: &amp;TreeNode[int]&#123;Val: 3&#125;,		&#125;,		Right: &amp;TreeNode[int]&#123;Val: 5&#125;,	&#125;	// 泛型客户端通过接口使用	c := &amp;BinaryTree[int]&#123;Root: root&#125;	it := c.CreateIterator() // Iterator[*TreeNode[int]]	for !it.IsEnd() &#123;		fmt.Printf(&quot;%d &quot;, it.GetCur().Val)	&#125;	// 输出: 1 2 3 4 5&#125;

类图：

    classDiagram
    class Iterator {
        &lt;&lt;interface&gt;&gt;
        +IsEnd() bool
        +GetCur() E
    }
    class Collection {
        &lt;&lt;interface&gt;&gt;
        +CreateIterator() Iterator[E]
    }
    class TreeNode {
        +Val T
        +Left *TreeNode[T]
        +Right *TreeNode[T]
    }
    class BinaryTree {
        +Root *TreeNode[T]  
    }
    class InOrderIterator {
        -stack []*TreeNode[T]
        -pushLeft(node *TreeNode[T])
        +IsEnd() bool
        +GetCur() *TreeNode[T]+
    }
    Iterator &lt;|.. InOrderIterator
    Collection &lt;|.. BinaryTree
    TreeNode &quot;1&quot; &lt;--* &quot;*&quot; BinaryTree : node
    Collection ..&gt; Iterator : Creates

1. 什么是中介者模式？中介者模式（Mediator Pattern）通过引入一个“中介者”对象来封装对象之间的交互，使多个对象不需要显式引用彼此，改为只与中介者通信。它将协作编排从同事对象中抽离出来，降低耦合并集中管理交互规则。 2. 为什么需要中介者模式？一个复杂的软件系统，若每个对象都与其他许多对象直接关联，则它们之间产生了紧密的耦合。这种设计的后果是，对任何一个对象的修改都可能引发连锁反应，迫使其他相关对象也得跟着改动，这便是“牵一发而动全身”的困境。系统的维护成本因此急剧攀升。 更糟糕的是，完整的业务流程被切割得支离破碎，散落在各个对象的实现中。想要理解一个完整的协作过程，开发者不得不深入多个类，追踪复杂的调用链，这使得系统的整体行为变得难以把握，也让新功能的添加或问题排查变得困难。同时，由于每个对象都和它的“同事们”绑得太死，想把它单独拿出来在别处复用也几乎不可能。 中介者模式正是为了解开这个“死结”而提出的。它引入了一个中心协调者——“中介者”，所有对象不再互相直接通信，而是统一与中介者对话。中介者负责接收消息，并根据既定规则将其分发给正确的对象。这样，原本混乱的网状结构被重构为清晰的“星型结构”，所有复杂的交互逻辑都集中到了中介者内部。通过这种方式，对象之间得以解耦，系统也因此变得更加清晰、易于维护和扩展。 3. 中介者模式的实现（go）下面用一个简化的聊天室演示中介者如何协调用户之间的消息传递。 package mainimport ( &quot;fmt&quot;)type Mediator interface &#123; Register(c Colleague) Send(from string, to string, msg string) Broadcast(from string, msg string)&#125;type Colleague interface &#123; Name() string Receive(from string, msg string) Send(to string, msg string) Broadcast(msg string)&#125;type ChatRoom struct &#123; members map[string]Colleague&#125;func NewChatRoom() *ChatRoom &#123; return &amp;ChatRoom&#123;members: make(map[string]Colleague)&#125;&#125;func (r *ChatRoom) Register(c Colleague) &#123; r.members[c.Name()] = c&#125;func (r *ChatRoom) Send(from string, to string, msg string) &#123; if m, ok := r.members[to]; ok &#123; m.Receive(from, msg) &#125;&#125;func (r *ChatRoom) Broadcast(from string, msg string) &#123; for name, m := range r.members &#123; if name == from &#123; continue &#125; m.Receive(from, msg) &#125;&#125;type User struct &#123; name string room *ChatRoom&#125;func NewUser(name string, room *ChatRoom) *User &#123; return &amp;User&#123;name: name, room: room&#125;&#125;func (u *User) Name() string &#123; return u.name &#125;func (u *User) Receive(from string, msg string) &#123; fmt.Printf(&quot;[%s] &lt;- %s: %s\n&quot;, u.name, from, msg)&#125;func (u *User) Send(to string, msg string) &#123; u.room.Send(u.name, to, msg)&#125;func (u *User) Broadcast(msg string) &#123; u.room.Broadcast(u.name, msg)&#125;func main() &#123; room := NewChatRoom() alice := NewUser(&quot;alice&quot;, room) bob := NewUser(&quot;bob&quot;, room) eve := NewUser(&quot;eve&quot;, room) room.Register(alice) room.Register(bob) room.Register(eve) alice.Send(&quot;bob&quot;, &quot;Hi Bob&quot;) bob.Send(&quot;alice&quot;, &quot;Hi Alice&quot;) eve.Broadcast(&quot;Hello everyone&quot;)&#125;
要点：用户之间不直接互相引用，交互规则集中在 ChatRoom。当需要增加记录审计、敏感词过滤、分组路由时，仅需扩展中介者。 类图：
classDiagram class mediator { &lt;&lt;interface&gt;&gt; +Register(c colleague) +Send(from,to,msg) +Broadcast(from,msg) } class concreteMediator { +Register(c colleague) +Send(from,to,msg) +Broadcast(from,msg) } class colleague { &lt;&lt;interface&gt;&gt; +Name() string +Receive(from,msg) +Send(to,msg) +Broadcast(msg) } class concreteColleague { +Name() string +Receive(from,msg) +Send(to,msg) +Broadcast(msg) }
mediator &lt;|.. concreteMediator colleague &lt;|.. concreteColleague concreteMediator --&gt; colleague : Register() concreteColleague --&gt; mediator : Send()&#x2F;Broadcast() concreteMediator --&gt; concreteColleague : Send()&#x2F;Broadcast()

1. 什么是备忘录模式？备忘录模式（Memento Pattern）用于在不破坏封装的前提下，捕获并保存对象的内部状态，以便之后将其恢复。核心思想是：状态快照应对外保持不透明，只有创建它的对象才能读写其内容。
2. 为什么需要备忘录模式？在需要撤销&#x2F;重做、事务性修改或阶段性试错的场景中，我们希望随时回到某个稳定的历史状态。如果将内部状态直接暴露给外部组件，会破坏封装并引入脆弱耦合。备忘录提供了一种更稳妥的做法：外部只负责保存与传递快照，而不窥视其内容；状态的读写权严格归属于原始对象本身。
3. 备忘录模式的实现（go）下面的实现采用“封装最严格”的变体：看护者只能看到窄接口 Memento，无法读取或修改状态；只有发起者可以访问具体备忘录以进行恢复。
type Memento interface&#123; mementoMarker() &#125;type memento struct&#123;    content string    cursor  int&#125;func (m *memento) mementoMarker()&#123;&#125;type Editor struct&#123;    content string    cursor  int&#125;func (e *Editor) SetContent(s string)&#123; e.content = s &#125;func (e *Editor) SetCursor(pos int)&#123; e.cursor = pos &#125;func (e *Editor) Save() Memento &#123; return &amp;memento&#123;content: e.content, cursor: e.cursor&#125; &#125;func (e *Editor) Restore(mem Memento)&#123; mm := mem.(*memento); e.content, e.cursor = mm.content, mm.cursor &#125;type History struct&#123; stack []Memento &#125;func (h *History) Push(m Memento)&#123; h.stack = append(h.stack, m) &#125;func (h *History) Pop() &#123;    if len(h.stack) == 0 &#123; return &#125;    i := len(h.stack)-1    m := h.stack[i]    h.stack = h.stack[:i]&#125;func (h *History) Top() Memento&#123;    if len(h.stack) == 0 &#123; return nil &#125;    return h.stack[len(h.stack)-1]&#125;

客户端代码如下：
func main()&#123;    e := &amp;Editor&#123;&#125;    h := &amp;History&#123;&#125;    e.SetContent(&quot;a&quot;); e.SetCursor(1); h.Push(e.Save())    e.SetContent(&quot;ab&quot;); e.SetCursor(2); h.Push(e.Save())    e.SetContent(&quot;abc&quot;); e.SetCursor(3)    h.Pop()    m := h.Top()    e.Restore(m)    fmt.Println(e.content, e.cursor)&#125;

输出：
ab 2

类图：

    classDiagram
class originator {
    +Save() Memento
    +Restore(m Memento)
}
class memento {
    &lt;&lt;interface&gt;&gt;
}
class concreteMemento {
    -state
}
class caretaker {
    +Push(Memento)
    +Pop() Memento
    +Top() Memento
}

originator ..&gt; memento : Save&#x2F;Restore
memento &lt;|.. concreteMemento
caretaker o-- memento : stores

1. 什么是观察者模式？观察者模式（Observer Pattern）用于在对象状态变化时，通知依赖它的多个观察者，实现一种一对多的订阅关系。被观察者只负责发布事件，不关心有多少观察者、它们如何处理，达到发布方与订阅方的解耦。
2. 为什么需要观察者模式？当一个对象的变化需要联动多个组件时，若直接在对象内部逐个调用这些组件，将产生紧耦合和复杂的依赖。当组件增删或行为变化时，被观察者也不得不调整。通过观察者模式，我们将事件的发布与处理分离：被观察者只负责发出信号，观察者各自处理，从而降低耦合、提高扩展性。
3. 观察者模式的实现（go）type Observer interface &#123;    Update(event string, data any)&#125;type Subject interface &#123;    Register(o Observer)    Unregister(o Observer)    Notify(event string, data any)&#125;type Topic struct &#123;    observers []Observer&#125;func (t *Topic) Register(o Observer) &#123;    t.observers = append(t.observers, o)&#125;func (t *Topic) Unregister(o Observer) &#123;    i := -1    for idx, ob := range t.observers &#123;        if ob == o &#123;            i = idx            break        &#125;    &#125;    if i &gt;= 0 &#123;        t.observers = append(t.observers[:i], t.observers[i+1:]...)    &#125;&#125;func (t *Topic) Notify(event string, data any) &#123;    for _, o := range t.observers &#123;        o.Update(event, data)    &#125;&#125;type PrintObserver struct &#123;    name string&#125;func (p *PrintObserver) Update(event string, data any) &#123;    fmt.Printf(&quot;[%s] %s: %v\n&quot;, p.name, event, data)&#125;

客户端代码如下：
func main() &#123;    t := &amp;Topic&#123;&#125;    a := &amp;PrintObserver&#123;name: &quot;A&quot;&#125;    b := &amp;PrintObserver&#123;name: &quot;B&quot;&#125;    t.Register(a)    t.Register(b)    t.Notify(&quot;price_changed&quot;, 42)    t.Unregister(a)    t.Notify(&quot;price_changed&quot;, 43)&#125;

输出：
[A] price_changed: 42[B] price_changed: 42[B] price_changed: 43

类图：

    classDiagram
class subject {
    &lt;&lt;interface&gt;&gt;
    +Register(o observer)
    +Unregister(o observer)
    +Notify(event,data)
}
class concreteSubject {
    +Register(o observer)
    +Unregister(o observer)
    +Notify(event,data)
}
class observer {
    &lt;&lt;interface&gt;&gt;
    +Update(event,data)
}
class concreteObserver {
    +Update(event,data)
